DROP TRIGGER IF EXISTS tbiu_sc_mem_m_member_work_info ON sc_mem_m_member_work_info CASCADE;
CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_mem_m_member_work_info() RETURNS trigger AS $BODY$
BEGIN
--return ;
  if coalesce(NEW.membership_no::text, '') = '' then
    CALL spa_dberrcol('sc_mem_m_member_work_info','membership_no',NEW.membership_no);
  end if;

  if coalesce(NEW.occupation_code::text, '') = '' then
    NEW.occupation_code  := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','occupation_code');
  end if;

  if coalesce(NEW.department_code::text, '') = '' then
    NEW.department_code  := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','department_code');
  end if;

  if coalesce(NEW.section_code::text, '') = '' then
    NEW.section_code := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','section_code');
  end if;

  if coalesce(NEW.subsection_code::text, '') = '' then
    NEW.subsection_code := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','subsection_code');
  end if;

  if coalesce(NEW.position_code::text, '') = '' then
    NEW.position_code := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','position_code');
  end if;

  if coalesce(NEW.level_code::text, '') = '' then NEW.level_code := 0;end if;
  if coalesce(NEW.salary_rate_code::text, '') = '' then NEW.salary_rate_code := 0;end if;

  if coalesce(NEW.employee_status::text, '') = '' then
    NEW.employee_status := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','employee_status');
  end if;

  if coalesce(NEW.salary_amount::text, '') = '' then NEW.salary_amount :=0;end if;

--2web - เงินเดือนสามารถแก้ไขได้ กรณีคีย์ผิด ไม่ควรที่จะมา error ตรงนี้ ควรจะแจ้งเตื่อนที่ app
--    if :old.salary_amount is null or :old.salary_amount != :new.salary_amount then
--      if :new.salary_amount < 0 then
--        spa_dberrcol('sc_mem_m_member_work_info','salary_amount',:new.salary_amount);
--      end if;
--  end if;
  if coalesce(NEW.work_branch::text, '') = '' then
    NEW.work_branch := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','work_branch');
  end if;

  if coalesce(NEW.retire_status::text, '') = '' or NEW.retire_status = ' ' then NEW.retire_status := '0';end if;

  if coalesce(NEW.group_position::text, '') = '' then
    NEW.group_position := pka_srv_dbattrib.getdefault('sc_mem_m_member_work_info','group_position');
  end if;

  --แก้ไข เงินเดือน
  if ( (OLD.salary_amount IS NOT NULL AND OLD.salary_amount::text <> '') and NEW.salary_amount <> OLD.salary_amount or
       (OLD.academic_salary IS NOT NULL AND OLD.academic_salary::text <> '') and NEW.academic_salary <> OLD.academic_salary or
       (OLD.remuneration_amount IS NOT NULL AND OLD.remuneration_amount::text <> '') and NEW.remuneration_amount <> OLD.remuneration_amount or
       (OLD.salary_real IS NOT NULL AND OLD.salary_real::text <> '') and NEW.salary_real <> OLD.salary_real )  then
    --insert  sc_mem_edit_salary
   INSERT INTO sc_mem_edit_salary( membership_no,           entry_date,             entry_id,   
           operate_date,                
           pre_salary_amount,       
           salary_amount,             entry_br,
           pre_academic_salary,     pre_remuneration_amount,        pre_salary_real,
           academic_salary,         remuneration_amount,            salary_real )  
  VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.salary_amount,        
           NEW.salary_amount,       current_setting('app.login_br', true),
           OLD.academic_salary,    OLD.remuneration_amount,       OLD.salary_real,
           NEW.academic_salary,    NEW.remuneration_amount,       NEW.salary_real
           ) 
;
  end if;
  --Niorn 2002-02-09 Amnat กั้นยอดเรียกเก็บ 
  --Niorn 2023-06-28 TGE ส่งหักไม่เกิน ห้ามเป็น 0
  if coalesce(NEW.salary_keep_limit::text, '') = '' or NEW.salary_keep_limit = 0 then
    NEW.salary_keep_limit  := 999999;
  end if;

  --แก้ไข กั้นยอด
  if ( (OLD.salary_keep_limit IS NOT NULL AND OLD.salary_keep_limit::text <> '') and NEW.salary_keep_limit <> OLD.salary_keep_limit )  then
    --insert  sc_mem_edit_salary_keep_limit
   INSERT INTO sc_mem_edit_salary_keep_limit( membership_no,           entry_date,             entry_id,   
           operate_date,                
           pre_salary_keep_limit,       
           salary_keep_limit,             entry_br )  
  VALUES ( NEW.membership_no,        statement_timestamp(),               current_setting('app.login_id', true),   
           TO_DATE( statement_timestamp() ),              
           OLD.salary_keep_limit,        
           NEW.salary_keep_limit,       current_setting('app.login_br', true) 
           ) 
;
  end if;

RETURN NEW;
end
